import{_ as i,o as e,c as l,a2 as s}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Alta disponibilidad","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/08-alta-disponibilidad.md","filePath":"bases-de-datos/redis/08-alta-disponibilidad.md","lastUpdated":1782521464000}'),r={name:"bases-de-datos/redis/08-alta-disponibilidad.md"};function o(n,a,t,c,d,p){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="alta-disponibilidad" tabindex="-1">Alta disponibilidad <a class="header-anchor" href="#alta-disponibilidad" aria-label="Permalink to &quot;Alta disponibilidad&quot;">​</a></h1><p>La alta disponibilidad en Redis busca reducir caidas y perdida de servicio. No elimina la necesidad de backups ni de disenar bien la aplicacion.</p><h2 id="replicacion" tabindex="-1">Replicacion <a class="header-anchor" href="#replicacion" aria-label="Permalink to &quot;Replicacion&quot;">​</a></h2><p>Redis puede tener replicas de lectura:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>primary -&gt; replica 1</span></span>
<span class="line"><span>        -&gt; replica 2</span></span></code></pre></div><p>Las replicas ayudan con lectura y recuperacion, pero la replicacion es asincrona. Puede haber perdida de datos recientes si el primary falla.</p><h2 id="sentinel" tabindex="-1">Sentinel <a class="header-anchor" href="#sentinel" aria-label="Permalink to &quot;Sentinel&quot;">​</a></h2><p>Redis Sentinel monitoriza instancias y puede promover una replica cuando cae el primary.</p><p>Funciones:</p><ul><li>Monitorizacion.</li><li>Notificacion.</li><li>Failover automatico.</li><li>Descubrimiento del primary actual.</li></ul><h2 id="cluster" tabindex="-1">Cluster <a class="header-anchor" href="#cluster" aria-label="Permalink to &quot;Cluster&quot;">​</a></h2><p>Redis Cluster reparte datos por slots entre varios nodos.</p><p>Sirve para:</p><ul><li>Escalar memoria.</li><li>Escalar throughput.</li><li>Tener failover por shards.</li></ul><p>Implica mas complejidad: no todas las operaciones multiclave funcionan igual si las claves viven en slots distintos.</p><h2 id="backups-vs-replicas" tabindex="-1">Backups vs replicas <a class="header-anchor" href="#backups-vs-replicas" aria-label="Permalink to &quot;Backups vs replicas&quot;">​</a></h2><p>Una replica copia tambien errores logicos:</p><ul><li><code>DEL</code> accidental.</li><li>Corrupcion de datos por bug.</li><li>Expiraciones mal configuradas.</li></ul><p>Por eso replica no sustituye a backup.</p><h2 id="clientes" tabindex="-1">Clientes <a class="header-anchor" href="#clientes" aria-label="Permalink to &quot;Clientes&quot;">​</a></h2><p>La aplicacion debe soportar:</p><ul><li>Reconexiones.</li><li>Timeouts.</li><li>Reintentos con backoff.</li><li>Descubrimiento de primary.</li><li>Errores temporales durante failover.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa servicios gestionados si no tienes experiencia operando Redis.</li><li>Prueba failover.</li><li>Monitoriza lag de replicas.</li><li>Configura timeouts en clientes.</li><li>Manten backups aunque haya replicas.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Pensar que replica equivale a consistencia inmediata.</li><li>No probar caidas.</li><li>Usar operaciones multiclave sin considerar cluster.</li><li>No configurar timeouts.</li><li>Desplegar Sentinel sin quorum adecuado.</li></ul>`,26)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
